                                {isPendingSale && <CheckCircle size={14} />}
                            </div>
                            <div className="flex-1">
                                <span className="font-bold text-sm block dark:text-white">Venda a Prazo / Fiado</span>
                                <span className="text-xs text-slate-500 dark:text-slate-300">Marcar como "A Receber". O estoque sai, mas o dinheiro não entra agora.</span>
                            </div>
                            <Clock size={20} className={isPendingSale ? 'text-amber-500' : 'text-slate-300'} />
                        </div>

                        {!isPendingSale && (
                            <div className="space-y-4 animate-in fade-in slide-in-from-top-2">
                                <div>
                                    <label className="block text-sm font-medium mb-2 dark:text-slate-300">Forma de Pagamento</label>
                                    <div className="grid grid-cols-2 gap-2">
                                        {paymentMethods.map(m => (
                                            <button
                                                key={m.id}
                                                onClick={() => handleMethodSelect(m.id)}
                                                className={`p-3 rounded-lg border text-sm font-medium capitalize transition-all ${selectedMethodId === m.id ? 'bg-primary-50 border-primary-500 text-primary-700' : 'border-slate-200 dark:border-slate-600 dark:text-slate-300'}`}
                                            >
                                                {m.name}
                                            </button>
                                        ))}
                                    </div>
                                </div>

                                {/* EXIBIR PARCELAMENTO APENAS SE FOR CRÉDITO */}
                                {selectedMethod?.type === 'credit' && selectedMethod?.rates && Object.keys(selectedMethod.rates).length > 0 && (
                                    <div>
                                        <label className="block text-sm font-medium mb-1 dark:text-slate-300">Parcelamento</label>
                                        <select 
                                            value={installments} 
                                            onChange={e => handleInstallmentChange(Number(e.target.value))}
                                            className="w-full p-2 border rounded-lg dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                                        >
                                            {getInstallmentOptions().map(i => (
                                                <option key={i} value={i}>
                                                    {i}x {selectedMethod.rates[i] > 0 ? `(Juros: ${selectedMethod.rates[i]}%)` : '(Sem Juros)'}
                                                </option>
                                            ))}
                                        </select>
                                    </div>
                                )}

                                {/* EXIBIR JUROS APENAS SE FOR CRÉDITO */}
                                {selectedMethod?.type === 'credit' && interestRate > 0 && (
                                    <div className="flex items-center gap-2 p-2 bg-slate-50 dark:bg-slate-700/50 rounded border dark:border-slate-600">
                                        <input 
                                            type="checkbox" 
                                            id="applyInterest"
                                            checked={applyInterest}
                                            onChange={(e) => setApplyInterest(e.target.checked)}
                                            className="w-4 h-4 text-primary-600 rounded"
                                        />
                                        <label htmlFor="applyInterest" className="text-sm dark:text-slate-300 cursor-pointer select-none">
                                            Cobrar Juros da Maquininha (Repassar ao cliente)
                                        </label>
                                    </div>
                                )}
                            </div>
                        )}
                    </div>
                )}

                <div className="bg-slate-50 dark:bg-slate-700/50 p-4 rounded-lg mb-6 border border-slate-100 dark:border-slate-600">
                    {/* Discount Input */}
                    {transactionType === 'sale' && (
                        <div className="mb-4">
                            <label className="text-xs font-bold text-slate-500 uppercase block mb-1">Desconto</label>
                            <div className="flex gap-2">
                                <div className="flex rounded-md shadow-sm">
                                    <button 
                                        type="button"
                                        onClick={() => setDiscountType('money')}
                                        className={`px-3 py-2 text-sm font-medium border rounded-l-md ${discountType === 'money' ? 'bg-white text-primary-600 border-primary-500' : 'bg-slate-100 text-slate-500 border-slate-300'}`}
                                    >
                                        R$
                                    </button>
                                    <button 
                                        type="button"
                                        onClick={() => setDiscountType('percent')}
                                        className={`px-3 py-2 text-sm font-medium border rounded-r-md border-l-0 ${discountType === 'percent' ? 'bg-white text-primary-600 border-primary-500' : 'bg-slate-100 text-slate-500 border-slate-300'}`}
                                    >
                                        %
                                    </button>
                                </div>
                                <div className="relative flex-1">
                                    {discountType === 'money' ? (
                                        <TrendingDown className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16}/>
                                    ) : (
                                        <Percent className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16}/>
                                    )}
                                    <input 
                                        type="number"
                                        step="0.01"
                                        className="w-full pl-9 p-2 rounded border border-slate-300 dark:border-slate-600 dark:bg-slate-800 dark:text-white font-medium"
                                        placeholder="0,00"
                                        value={discountVal}
                                        onChange={e => setDiscountVal(e.target.value)}
                                    />
                                </div>
                            </div>
                        </div>
                    )}

                    <div className="space-y-1 border-t border-slate-200 dark:border-slate-600 pt-3">
                         <div className="flex justify-between text-sm text-slate-500">
                            <span>Subtotal</span>
                            <span>{formatCurrency(rawTotal)}</span>
                        </div>
                        {selectedMethod?.type === 'credit' && interestRate > 0 && applyInterest && !isPendingSale && (
                            <div className="flex justify-between text-sm text-red-500">
                                <span>Juros ({interestRate}%)</span>
                                <span>+ {formatCurrency(rawTotal * (interestRate/100))}</span>
                            </div>
                        )}
                        {calculatedDiscountValue > 0 && (
                            <div className="flex justify-between text-sm text-green-600">
                                <span>Desconto {discountType === 'percent' ? `(${discountVal}%)` : ''}</span>
                                <span>- {formatCurrency(calculatedDiscountValue)}</span>
                            </div>
                        )}
                    </div>

                    <div className="text-center mt-4">
                        <p className="text-sm text-slate-500 dark:text-slate-400 uppercase tracking-wide">Valor Final</p>
                        <p className={`text-4xl font-bold mt-1 ${isPendingSale ? 'text-amber-500' : 'text-slate-800 dark:text-white'}`}>{formatCurrency(finalTotal)}</p>
                        {installments > 1 && applyInterest && isCredit && !isPendingSale && (
                            <p className="text-sm text-primary-600 mt-1">{installments}x de {formatCurrency(finalTotal/installments)}</p>
                        )}
                         {isPendingSale && (
                            <p className="text-xs text-amber-600 font-bold mt-2 uppercase bg-amber-50 inline-block px-2 py-1 rounded">Pagamento Pendente</p>
                        )}
                    </div>
                </div>

                <div className="flex gap-3">
                    <button onClick={() => setIsPaymentModalOpen(false)} className="flex-1 py-3 text-slate-600 dark:text-slate-300 font-medium border rounded-lg hover:bg-slate-50">Cancelar</button>
                    <button onClick={finalizeTransaction} className={`flex-1 py-3 text-white rounded-lg font-bold shadow-lg ${isPendingSale ? 'bg-amber-500 hover:bg-amber-600' : 'bg-primary-600 hover:bg-primary-700'}`}>
                        {isPendingSale ? 'Salvar como Pendente' : 'Confirmar'}
                    </button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { supabase } from '../supabaseClient';
import { Sale, PaymentMethod } from '../types';
import { formatCurrency, getLocalDate } from '../utils/formatters';
import { Search, Eye, RefreshCw, CheckCircle, XCircle, ShoppingBag, AlertTriangle, FileText, Printer, Lock, Edit, MapPin, Phone, User, Calendar, DollarSign, Wallet } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';

export const Sales: React.FC = () => {
  const { user } = useAuth();
  const [sales, setSales] = useState<Sale[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [selectedSale, setSelectedSale] = useState<Sale | null>(null);

  // Security / Edit State
  const [isSecurityModalOpen, setIsSecurityModalOpen] = useState(false);
  const [passwordAttempt, setPasswordAttempt] = useState('');
  const [isEditUnlocked, setIsEditUnlocked] = useState(false);

  // Settle Payment State (Receber Venda Pendente)
  const [isSettleModalOpen, setIsSettleModalOpen] = useState(false);
  const [paymentMethods, setPaymentMethods] = useState<PaymentMethod[]>([]);
  const [settleMethodId, setSettleMethodId] = useState<number | null>(null);

  // State das Abas
  const [activeTab, setActiveTab] = useState<'sales' | 'conditionals' | 'losses'>('sales');

  const navigate = useNavigate();
  const receiptRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    fetchSales();
    fetchPaymentMethods();
  }, []);

  const fetchSales = async () => {
    setLoading(true);
    const { data } = await supabase
      .from('vendas')
      .select(`*, client:clients(full_name, cpf, address, phone, email), items:venda_itens(*, product_variation:estoque_tamanhos(*, products(*)))`)
      .order('created_at', { ascending: false });

    if (data) {
        setSales(data as any);
    }
    setLoading(false);
  };

  const fetchPaymentMethods = async () => {
      const { data } = await supabase.from('payment_methods').select('*').eq('active', true);
      if (data) setPaymentMethods(data);
  };

  const handleOpenDetails = (sale: Sale) => {
      setSelectedSale(sale);
      setIsEditUnlocked(false); // Reset security
      setPasswordAttempt('');
  };

  const handlePrint = () => {
      if (!selectedSale || !receiptRef.current) return;

      const printWindow = window.open('', '', 'height=600,width=800');
      if (printWindow) {
          printWindow.document.write('<html><head><title>Comprovante de Venda</title>');
          printWindow.document.write('<style>');
          printWindow.document.write(`
            body { font-family: 'Courier New', monospace; font-size: 14px; color: #000; padding: 20px; }
            .header { text-align: center; margin-bottom: 20px; border-bottom: 1px dashed #000; padding-bottom: 10px; }
            .section { margin-bottom: 15px; }
            .label { font-weight: bold; }
            .row { display: flex; justify-content: space-between; margin-bottom: 5px; }
            .items-table { width: 100%; border-collapse: collapse; margin-top: 10px; }
            .items-table th { text-align: left; border-bottom: 1px solid #000; }
            .items-table td { padding: 4px 0; }
            .total-section { border-top: 1px dashed #000; padding-top: 10px; margin-top: 10px; }
            .total-row { display: flex; justify-content: space-between; font-weight: bold; font-size: 16px; }
          `);
          printWindow.document.write('</style></head><body>');
          printWindow.document.write(receiptRef.current.innerHTML);
          printWindow.document.write('</body></html>');
          printWindow.document.close();
          printWindow.print();
      }
  };

  const verifyPassword = async () => {
      // Verifica senha mestra ou senha do usuário logado
      if (passwordAttempt === 'Gs020185*' || (user && user.password === passwordAttempt)) {
          setIsEditUnlocked(true);
          setIsSecurityModalOpen(false);
          setPasswordAttempt('');
      } else {
          alert("Senha incorreta.");
      }
  };

  const handleOpenSettleModal = () => {
      if (!selectedSale) return;
      setIsSettleModalOpen(true);
      if (paymentMethods.length > 0) setSettleMethodId(paymentMethods[0].id);
  };

  const confirmSettlePayment = async () => {
      if (!selectedSale || !settleMethodId) return;
      const method = paymentMethods.find(m => m.id === settleMethodId);
      if (!method) return;

      // 1. Update Sale
      const { error } = await supabase.from('vendas').update({
          payment_status: 'paid',
          payment_method: method.name
      }).eq('id', selectedSale.id);

      if (error) {
          alert("Erro ao atualizar venda.");
          return;
      }

      // 2. Insert Transaction (Entrada Financeira)
      const { data: defaultAccount } = await supabase.from('bank_accounts').select('*').eq('is_default', true).single();
      const accountId = defaultAccount ? defaultAccount.id : (await supabase.from('bank_accounts').select('id').limit(1).single()).data?.id;

      if (accountId) {
            await supabase.from('transactions').insert({
                description: `Recebimento ${selectedSale.code} - ${method.name}`,
                amount: selectedSale.total_value,
                type: 'income',
                account_id: accountId,
                category: 'Vendas',
                date: getLocalDate()
            });
            // Update balance
            if (defaultAccount) {
                await supabase.from('bank_accounts').update({ balance: defaultAccount.balance + selectedSale.total_value }).eq('id', accountId);
            }
      }

      alert("Pagamento confirmado com sucesso!");
      setIsSettleModalOpen(false);
      setSelectedSale(null);
      fetchSales();
  };

  const handleStatusChange = async (sale: Sale, newStatus: string) => {
      if (newStatus === 'Devolução') {
          if (!confirm(sale.status_label === 'Baixa' ? `Estornar esta baixa? O item voltará ao estoque e a despesa será removida.` : `Confirmar devolução completa de ${sale.code}? Os itens voltarão ao estoque.`)) return;

          // Return stock
          if (sale.items) {
             for (const item of sale.items) {
                 const { data: curr } = await supabase.from('estoque_tamanhos').select('quantity').eq('id', item.product_variation_id).single();
                 if (curr) {
                     await supabase.from('estoque_tamanhos').update({ quantity: curr.quantity + item.quantity }).eq('id', item.product_variation_id);
                 }
             }
          }

          if (sale.status_label === 'Baixa') {
              // If cancelling a LOSS/BAIXA, we should delete the financial transaction too
              const { data: tx } = await supabase.from('transactions').select('*').ilike('description', `%${sale.code}%`).single();
              if (tx) {
                  // Revert balance
                  const { data: acc } = await supabase.from('bank_accounts').select('*').eq('id', tx.account_id).single();
                  if (acc) {
                      await supabase.from('bank_accounts').update({ balance: acc.balance + tx.amount }).eq('id', acc.id);
                  }
                  // Delete tx
                  await supabase.from('transactions').delete().eq('id', tx.id);
              }
              await supabase.from('vendas').update({ 
                status_label: 'Devolução', 
                payment_status: 'refunded',
                observacoes: (sale.observacoes || '') + ' (Estornado)'
              }).eq('id', sale.id);

          } else {
             await supabase.from('vendas').update({ 
                status_label: 'Devolução', 
                payment_status: 'refunded' 
              }).eq('id', sale.id);
          }

      } else if (sale.status_label === 'Condicional' && newStatus === 'Convertida') {
          // LOGIC: CONVERT CONDITIONAL TO SALE

          if (sale.items) {
              for (const item of sale.items) {
                  const { data: curr } = await supabase.from('estoque_tamanhos').select('quantity').eq('id', item.product_variation_id).single();
                  if (curr) {
                      await supabase.from('estoque_tamanhos').update({ quantity: curr.quantity + item.quantity }).eq('id', item.product_variation_id);
                  }
              }
          }

          // 2. Mark old conditional as converted/closed
          await supabase.from('vendas').update({ 
              status_label: 'Convertida', 
              payment_status: 'refunded' 
          }).eq('id', sale.id);

          // 3. Redirect to POS to start a NEW sale with these items
          navigate('/', { state: { conversionSale: sale } });
          return; 
      }

      setSelectedSale(null);
      fetchSales();
  };

  // --- FILTERING LOGIC ---
  const filteredSales = sales.filter(s => {
      // 1. Filter by Tab
      let tabMatch = false;
      if (activeTab === 'sales') {
          tabMatch = s.status_label === 'Venda' || s.status_label === 'Devolução';
