const getSizeWeight = (size: string) => {
  const weights: Record<string, number> = {
    'RN': 0, 'PB': 1, '1': 2, '2': 3, '3': 4, '4': 5, '6': 6, '8': 7, '10': 8, '12': 9, '14': 10, '16': 11,
    'PP': 20, 'P': 21, 'M': 22, 'G': 23, 'GG': 24, 'XG': 25, 'XXG': 26, 'U': 100
  };
  return weights[size.toUpperCase()] || 99;
};

export const POS: React.FC = () => {
  const { user } = useAuth();
  const [products, setProducts] = useState<Product[]>([]);
  const [search, setSearch] = useState('');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [selectedClient, setSelectedClient] = useState<string>('');

  // Payment Configs
  const [paymentMethods, setPaymentMethods] = useState<PaymentMethod[]>([]);
  const [selectedMethodId, setSelectedMethodId] = useState<number | null>(null);
  const [installments, setInstallments] = useState(1);
  const [interestRate, setInterestRate] = useState(0);
  const [applyInterest, setApplyInterest] = useState(true);

  // Pending Sale State (Fiado)
  const [isPendingSale, setIsPendingSale] = useState(false);

  // Discount States
  const [discountVal, setDiscountVal] = useState(''); 
  const [discountType, setDiscountType] = useState<'money' | 'percent'>('money');

  // Modals
  const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
  const [isNewClientModalOpen, setIsNewClientModalOpen] = useState(false);
  const [newClientData, setNewClientData] = useState({ full_name: '', cpf: '', phone: '', email: '', address: '' });

  // Discount Modal State (Item level)
  const [discountItemIndex, setDiscountItemIndex] = useState<number | null>(null);
  const [discountValue, setDiscountValue] = useState('');

  const [transactionType, setTransactionType] = useState<'sale' | 'quote'>('sale');
  const location = useLocation();
  const navigate = useNavigate();

  // Barcode Buffer
  const barcodeBuffer = useRef('');
  const lastKeyTime = useRef(0);

  useEffect(() => {
    loadData();
  }, []);

  // --- BARCODE SCANNER LISTENER ---
  useEffect(() => {
    const handleGlobalKeyDown = (e: KeyboardEvent) => {
        // Se estiver digitando em um input (exceto o de busca que tratamos separado, ou se não estiver focado), 
        // a lógica de buffer pode precisar de ajuste. Aqui assumimos que scanner funciona como teclado rápido.

        const target = e.target as HTMLElement;
        // Se o foco estiver no input de busca, deixamos ele lidar com o Enter, mas capturamos se não estiver focado em inputs de texto
        if (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA') {
             // Se for o input de busca, ok, ele tem o onKeyDown próprio.
             return; 
        }

        // Ignora se modais estiverem abertos
        if (isPaymentModalOpen || isNewClientModalOpen || discountItemIndex !== null) return;

        const currentTime = Date.now();
        const timeDiff = currentTime - lastKeyTime.current;
        lastKeyTime.current = currentTime;

        // Se for Enter, processa o buffer
        if (e.key === 'Enter') {
            if (barcodeBuffer.current.length > 0) {
                processBarcode(barcodeBuffer.current);
                barcodeBuffer.current = '';
            }
            return;
        }

        // Limpa buffer se demorar muito entre teclas (digitação manual vs scanner)
        // Scanners geralmente enviam caracteres em < 50ms
        if (timeDiff > 100) {
            barcodeBuffer.current = '';
        }

        // Adiciona caracteres imprimíveis (números/letras)
        if (e.key.length === 1) {
            barcodeBuffer.current += e.key;
        }
    };

    window.addEventListener('keydown', handleGlobalKeyDown);
    return () => window.removeEventListener('keydown', handleGlobalKeyDown);
  }, [products, isPaymentModalOpen, isNewClientModalOpen, discountItemIndex]);


  const processBarcode = (sku: string) => {
      if (!sku) return;
      const cleanSku = sku.trim().toUpperCase();

      // Procura produto pelo SKU
      let foundProduct: Product | undefined;
      let foundVariation: ProductVariation | undefined;

      // Iterar produtos e variações
      for (const p of products) {
          const v = p.variations?.find(variation => variation.sku && variation.sku.toUpperCase() === cleanSku);
          if (v) {
              foundProduct = p;
              foundVariation = v;
              break;
          }
      }

      if (foundProduct && foundVariation) {
          addToCart(foundProduct, foundVariation);
          // Feedback visual: limpar busca se o SKU veio de lá
          if (search.toUpperCase() === cleanSku) {
              setSearch('');
          }
      } else {
          // Opcional: Toast de erro
          console.log(`Produto com SKU ${sku} não encontrado.`);
      }
  };

  const loadData = async () => {
    const { data: prodData } = await supabase.from('products').select('*').eq('active', true);
    const { data: varData } = await supabase.from('estoque_tamanhos').select('*').gt('quantity', 0);
    const { data: clientData } = await supabase.from('clients').select('*').order('full_name');
    const { data: payMethods } = await supabase.from('payment_methods').select('*').eq('active', true);

    if (prodData && varData) {
      const rawProducts = prodData.map(p => ({
        ...p,
        variations: varData.filter(v => v.product_id === p.id)
      })).filter(p => p.variations && p.variations.length > 0);

      const groupedMap = new Map<string, Product>();

      rawProducts.forEach(p => {
        const normalizedName = p.nome.trim();
        if (groupedMap.has(normalizedName)) {
            const existing = groupedMap.get(normalizedName)!;
            existing.variations = [...(existing.variations || []), ...(p.variations || [])];
        } else {
            groupedMap.set(normalizedName, { ...p });
        }
      });

      const unifiedProducts = Array.from(groupedMap.values()).sort((a, b) => a.nome.localeCompare(b.nome));
      setProducts(unifiedProducts);
    }

    if (clientData) setClients(clientData);
    if (payMethods) setPaymentMethods(payMethods);
  };

  // --- HANDLE CONVERSION FROM SALES PAGE ---
  useEffect(() => {
      if (location.state?.conversionSale) {
          const sale = location.state.conversionSale;
          if (sale.client_id) setSelectedClient(sale.client_id);
          if (sale.items) {
              const convertedCart: CartItem[] = [];
              sale.items.forEach((item: any) => {
                  const variation = item.product_variation;
                  const product = variation?.products; 
                  if (variation && product) {
                      convertedCart.push({
                          product: product,
                          variation: variation,
                          quantity: item.quantity,
                          customPrice: item.unit_price
                      });
                  }
              });
              setCart(convertedCart);
          }
          navigate(location.pathname, { replace: true, state: {} });
      }
  }, [location.state, navigate]);

  const addToCart = (product: Product, variation: ProductVariation) => {
    setCart(prev => {
      const existingIndex = prev.findIndex(item => item.variation.id === variation.id);
      if (existingIndex >= 0) {
        const existing = prev[existingIndex];
        if (existing.quantity >= variation.quantity) {
            alert("Estoque insuficiente!");
            return prev;
        }
        const newCart = [...prev];
        newCart[existingIndex] = { ...existing, quantity: existing.quantity + 1 };
        return newCart;
      }
      return [...prev, { product, variation, quantity: 1 }];
    });
  };

  const removeFromCart = (index: number) => {
    setCart(prev => prev.filter((_, i) => i !== index));
  };

  const openDiscountModal = (index: number) => {
      setDiscountItemIndex(index);
      const currentPrice = cart[index].customPrice || cart[index].variation.price_sale;
      setDiscountValue(currentPrice.toString());
  };

  const applyDiscount = () => {
      if (discountItemIndex === null) return;
      const newVal = parseFloat(discountValue.replace(',', '.'));
      if (isNaN(newVal) || newVal < 0) return alert("Valor inválido");

      setCart(prev => {
          const newCart = [...prev];
          newCart[discountItemIndex] = { ...newCart[discountItemIndex], customPrice: newVal };
          return newCart;
      });
      setDiscountItemIndex(null);
  };

  const rawTotal = cart.reduce((acc, item) => acc + (item.customPrice || item.variation.price_sale) * item.quantity, 0);

  const discountInput = parseFloat(discountVal.replace(',', '.')) || 0;

  const selectedMethod = paymentMethods.find(m => m.id === selectedMethodId);
  const isCredit = selectedMethod?.type === 'credit';

  // Juros não se aplicam se for venda pendente (fiado)
  const subTotalWithInterest = (isCredit && applyInterest && !isPendingSale)
    ? rawTotal * (1 + (interestRate / 100)) 
    : rawTotal;

  const calculatedDiscountValue = discountType === 'percent' 
    ? subTotalWithInterest * (discountInput / 100)
    : discountInput;

  const finalTotal = Math.max(0, subTotalWithInterest - calculatedDiscountValue);

  const handleOpenPayment = (type: 'sale' | 'quote') => {
      if (!selectedClient) {
          alert("Por favor, selecione um cliente antes de finalizar.");
          return;
      }
      setTransactionType(type);
      setDiscountVal('');
      setDiscountType('money');
      setIsPendingSale(false); // Reset pendente
      setIsPaymentModalOpen(true);
      if (paymentMethods.length > 0) handleMethodSelect(paymentMethods[0].id);
  };

  const handleMethodSelect = (id: number) => {
      setSelectedMethodId(id);
      setInstallments(1);
      setApplyInterest(true); 
      const method = paymentMethods.find(m => m.id === id);
      if (method) {
          const rate = method.rates?.['1'] || 0;
          setInterestRate(rate);
      }
  };

  const handleInstallmentChange = (count: number) => {
      setInstallments(count);
      const method = paymentMethods.find(m => m.id === selectedMethodId);
      if (method) {
          const rate = method.rates?.[count.toString()] || 0;
          setInterestRate(rate);
      }
  };

  const finalizeTransaction = async () => {
    // 1. Get Code
    const prefix = transactionType === 'sale' ? 'V' : 'C';
    const { data: code } = await supabase.rpc('get_next_code', { prefix });

    const method = paymentMethods.find(m => m.id === selectedMethodId);
    const isCreditPayment = method?.type === 'credit';

    // Determina Status e Método
    const finalPaymentStatus = transactionType === 'sale' 
        ? (isPendingSale ? 'pending' : 'paid') 
        : 'pending'; // Condicionais sempre pending

    const finalMethodName = isPendingSale 
        ? 'A Receber' 
        : (method ? method.name : 'Outros');

    // 2. Create Header
    const { data: sale, error } = await supabase.from('vendas').insert({
        code: code, 
        client_id: selectedClient,
        user_id: user?.id || '00000000-0000-0000-0000-000000000000',
        total_value: finalTotal,
        payment_method: finalMethodName,
        payment_status: finalPaymentStatus,
        status_label: transactionType === 'sale' ? 'Venda' : 'Condicional',
        payment_details: { 
            installments: (isCreditPayment && !isPendingSale) ? installments : 1, 
            interest_rate: (isCreditPayment && applyInterest && !isPendingSale) ? interestRate : 0, 
            raw_value: rawTotal,
            method_type: isPendingSale ? 'pending' : method?.type,
            interest_applied: (isCreditPayment && applyInterest && !isPendingSale),
            discount_applied: calculatedDiscountValue,
            discount_type: discountType
        }
    }).select().single();

    if (error || !sale) {
        alert("Erro ao finalizar: " + (error?.message || 'Desconhecido'));
        return;
    }

    // 3. Items
    const saleItems = cart.map(item => ({
        sale_id: sale.id,
        product_variation_id: item.variation.id,
        quantity: item.quantity,
        unit_price: item.customPrice || item.variation.price_sale,
        original_cost: item.variation.price_cost
    }));

    await supabase.from('venda_itens').insert(saleItems);

    // 4. Update Stock & Financial (if Sale)
    for (const item of cart) {
        const { data: currentVar } = await supabase.from('estoque_tamanhos').select('quantity').eq('id', item.variation.id).single();
        if(currentVar) {
            await supabase.from('estoque_tamanhos').update({ quantity: currentVar.quantity - item.quantity}).eq('id', item.variation.id);
        }
    }

    // Create transaction record for cash flow ONLY IF it is a paid sale (Not pending, Not Quote)
    if (transactionType === 'sale' && !isPendingSale && method) {
        // Retrieve default account
        const { data: defaultAccount } = await supabase.from('bank_accounts').select('*').eq('is_default', true).single();
        const accountId = defaultAccount ? defaultAccount.id : (await supabase.from('bank_accounts').select('id').limit(1).single()).data?.id;

        if (accountId) {
             await supabase.from('transactions').insert({
                 description: `Venda ${code} - ${method.name}`,
                 amount: finalTotal,
                 type: 'income',
                 account_id: accountId,
                 category: 'Vendas',
                 date: getLocalDate()
             });
             // Update account balance
             if (defaultAccount) {
                 await supabase.from('bank_accounts').update({ balance: defaultAccount.balance + finalTotal }).eq('id', accountId);
             }
        }
    }

    const msg = isPendingSale 
        ? `Venda ${code} registrada como PENDENTE (Fiado). Estoque atualizado.` 
        : `${transactionType === 'sale' ? 'Venda' : 'Condicional'} ${code} realizada com sucesso!`;

    alert(msg);

    // Clear State
    setCart([]);
    setIsPaymentModalOpen(false);
    setSelectedClient('');

    window.history.replaceState({}, document.title);
    navigate(location.pathname, { replace: true, state: {} });
    loadData();
  };

  const handleQuickSaveClient = async () => {
      if (!newClientData.full_name) return alert("Nome é obrigatório");
      const { data } = await supabase.from('clients').insert([newClientData]).select().single();
      if (data) {
          setClients(prev => [...prev, data].sort((a,b) => a.full_name.localeCompare(b.full_name)));
          setSelectedClient(data.id);
          setIsNewClientModalOpen(false);
          setNewClientData({ full_name: '', cpf: '', phone: '', email: '', address: '' });
      }
  };

  const filteredProducts = products.filter(p => 
    p.nome.toLowerCase().includes(search.toLowerCase()) || 
    p.variations?.some(v => v.model_variant.toLowerCase().includes(search.toLowerCase()) || v.sku.toLowerCase().includes(search.toLowerCase()))
  );

  const getInstallmentOptions = () => {
      if (!selectedMethod?.rates) return [];
      return Object.keys(selectedMethod.rates)
        .sort((a,b) => parseInt(a) - parseInt(b));
  };

  return (
    <div className="flex h-[calc(100vh-6rem)] gap-4">
      {/* Product Catalog */}
      <div className="flex-1 flex flex-col bg-white dark:bg-slate-800 rounded-lg shadow overflow-hidden">
        <div className="p-4 border-b border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-900/50">
          <div className="relative flex items-center gap-2">
            <div className="relative flex-1">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
                <input 
                className="w-full pl-10 pr-4 py-2 bg-white dark:bg-slate-700 rounded-lg border border-slate-200 dark:border-slate-600 dark:text-white"
                placeholder="Buscar por nome ou bipar código (SKU)..."
                value={search}
                onChange={e => setSearch(e.target.value)}
                onKeyDown={(e) => {
                    if (e.key === 'Enter') processBarcode(search);
                }}
                autoFocus
                />
            </div>
            <div className="p-2 bg-slate-200 dark:bg-slate-700 rounded text-slate-500 dark:text-slate-400" title="Leitor de Código de Barras Ativo">
                <ScanBarcode size={20} />
            </div>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-4 bg-slate-100 dark:bg-slate-900/20">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 2xl:grid-cols-4 gap-4">
                {filteredProducts.map(product => {
                    if (!product.variations) return null;
                    const variationsByModel: Record<string, ProductVariation[]> = {};
                    product.variations.forEach(v => {
                        const key = v.model_variant || 'Padrão';
                        if (!variationsByModel[key]) variationsByModel[key] = [];
                        variationsByModel[key].push(v);
                    });

                    return (
                        <div key={product.id} className="bg-slate-50 dark:bg-slate-700/50 rounded-lg border border-slate-200 dark:border-slate-700 hover:shadow-lg transition-all flex flex-col overflow-hidden">
                            <div className="p-3 bg-white dark:bg-slate-800 border-b border-slate-100 dark:border-slate-600">
                                <h3 className="font-bold text-slate-800 dark:text-white leading-tight">{product.nome}</h3>
                                <p className="text-xs text-slate-500 mt-1">{product.categoria}</p>
                            </div>
                            <div className="flex-1 overflow-y-auto max-h-60 p-3 space-y-4">
                                {Object.keys(variationsByModel).sort().map(model => (
                                    <div key={model} className="space-y-2">
                                        <div className="border-b border-slate-200 dark:border-slate-600 pb-1">
                                            <span className="text-xs font-bold text-slate-600 dark:text-slate-300 uppercase">{model}</span>
                                        </div>
                                        <div className="flex flex-wrap gap-2">
                                            {variationsByModel[model].sort((a,b) => getSizeWeight(a.size) - getSizeWeight(b.size)).map(v => (
                                                <button 
                                                    key={v.id} 
                                                    onClick={() => addToCart(product, v)} 
                                                    className="flex flex-col items-center justify-center bg-white dark:bg-slate-600 border border-slate-200 dark:border-slate-500 rounded p-1 min-w-[3.5rem] min-h-[3.5rem] hover:border-primary-500 shadow-sm transition-all"
                                                >
                                                    <div className="flex items-center gap-1">
                                                        <span className="font-bold text-sm text-slate-800 dark:text-white">{v.size}</span>
                                                        <span className={`text-[10px] font-medium ${v.quantity < 2 ? 'text-red-500' : 'text-slate-400'}`}>
                                                            ({v.quantity})
                                                        </span>
                                                    </div>
                                                    <span className="text-[10px] text-slate-500 dark:text-slate-400 font-medium mt-0.5">{formatCurrency(v.price_sale)}</span>
                                                </button>
                                            ))}
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
      </div>

      {/* Cart Sidebar */}
      <div className="w-96 bg-white dark:bg-slate-800 rounded-lg shadow flex flex-col border-l border-slate-200 dark:border-slate-700">
        <div className="p-4 bg-slate-50 dark:bg-slate-900/50 flex justify-between items-center border-b border-slate-200 dark:border-slate-700">
            <h2 className="font-bold text-lg dark:text-white flex items-center"><ShoppingBag className="mr-2" size={20}/> Carrinho</h2>
            <span className="bg-primary-100 text-primary-700 px-2 py-1 rounded text-sm font-bold">{cart.length} itens</span>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-4">
            {cart.map((item, idx) => (
                <div key={`${item.variation.id}-${idx}`} className="flex justify-between items-start border-b border-slate-100 dark:border-slate-700 pb-2">
                    <div className="flex-1">
                        <p className="font-medium text-slate-800 dark:text-white text-sm">{item.product.nome}</p>
                        <p className="text-xs text-slate-500">{item.variation.model_variant} | Tam: <b>{item.variation.size}</b></p>
                        <div className="flex items-center gap-2 mt-1">
                             <p className="text-xs font-bold text-primary-600">{formatCurrency(item.customPrice || item.variation.price_sale)}</p>
                             {item.customPrice && item.customPrice !== item.variation.price_sale && (
                                 <span className="text-[10px] line-through text-slate-400">{formatCurrency(item.variation.price_sale)}</span>
                             )}
                        </div>
                    </div>
                    <div className="flex items-center gap-2">
                        <button 
                            onClick={() => openDiscountModal(idx)}
                            className="text-slate-400 hover:text-blue-500 p-1 rounded"
                            title="Editar Preço (Desconto)"
                        >
                            <Tag size={16} />
                        </button>
                        <span className="font-mono font-bold text-slate-700 dark:text-slate-300 text-sm">x{item.quantity}</span>
                        <button onClick={() => removeFromCart(idx)} className="text-red-400 hover:text-red-600 p-1"><Trash size={16} /></button>
                    </div>
                </div>
            ))}
        </div>

        <div className="p-4 bg-slate-50 dark:bg-slate-900/50 border-t border-slate-200 dark:border-slate-700 space-y-4">
            <div className="relative flex gap-2">
                <div className="relative flex-1">
                    <User className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                    <select 
                        className={`w-full pl-9 p-2 text-sm rounded border ${!selectedClient ? 'border-red-300 bg-red-50' : 'border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-700'} dark:text-white`}
                        value={selectedClient}
                        onChange={e => setSelectedClient(e.target.value)}
                    >
                        <option value="">Selecione um Cliente *</option>
                        {clients.map(c => <option key={c.id} value={c.id}>{c.full_name}</option>)}
                    </select>
                </div>
                <button onClick={() => setIsNewClientModalOpen(true)} className="p-2 bg-primary-100 text-primary-600 rounded hover:bg-primary-200" title="Novo Cliente"><UserPlus size={20} /></button>
            </div>

            {!selectedClient && (
                <div className="text-xs text-red-500 flex items-center justify-center bg-red-50 p-1 rounded">
                    <AlertCircle size={12} className="mr-1"/> Obrigatório selecionar cliente
                </div>
            )}

            <div className="flex justify-between items-end">
                <span className="text-slate-500 dark:text-slate-400 font-medium">Total</span>
                <span className="text-3xl font-bold text-slate-800 dark:text-white">{formatCurrency(rawTotal)}</span>
            </div>

            <div className="grid grid-cols-2 gap-3">
                <button onClick={() => handleOpenPayment('quote')} disabled={cart.length === 0} className="py-3 bg-amber-100 text-amber-800 rounded-lg font-bold border border-amber-200 disabled:opacity-50 text-sm">Condicional</button>
                <button onClick={() => handleOpenPayment('sale')} disabled={cart.length === 0} className="py-3 bg-primary-600 text-white rounded-lg font-bold shadow-lg disabled:opacity-50 text-sm">Finalizar</button>
            </div>
        </div>
      </div>

      {/* New Client Modal */}
      {isNewClientModalOpen && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/60 p-4 backdrop-blur-sm">
            <div className="bg-white dark:bg-slate-800 rounded-xl shadow-2xl w-full max-w-md overflow-hidden">
                <div className="p-4 bg-slate-50 dark:bg-slate-900/50 flex justify-between items-center border-b dark:border-slate-700">
                    <h3 className="font-bold dark:text-white flex items-center"><UserPlus size={18} className="mr-2"/> Cadastro Rápido</h3>
                    <button onClick={() => setIsNewClientModalOpen(false)}><X size={20} /></button>
                </div>
                <div className="p-4 space-y-3">
                    <input className="w-full p-2 border rounded dark:bg-slate-700 dark:border-slate-600 dark:text-white" placeholder="Nome Completo *" value={newClientData.full_name} onChange={e => setNewClientData({...newClientData, full_name: e.target.value})} />
                    <div className="grid grid-cols-2 gap-3">
                        <input className="p-2 border rounded dark:bg-slate-700 dark:border-slate-600 dark:text-white" placeholder="CPF" value={newClientData.cpf} onChange={e => setNewClientData({...newClientData, cpf: maskCPF(e.target.value)})} />
                        <input className="p-2 border rounded dark:bg-slate-700 dark:border-slate-600 dark:text-white" placeholder="Telefone" value={newClientData.phone} onChange={e => setNewClientData({...newClientData, phone: maskPhone(e.target.value)})} />
                    </div>

                    <input className="w-full p-2 border rounded dark:bg-slate-700 dark:border-slate-600 dark:text-white" placeholder="E-mail (Opcional)" value={newClientData.email} onChange={e => setNewClientData({...newClientData, email: e.target.value})} />
                    <textarea 
                        className="w-full p-2 border rounded dark:bg-slate-700 dark:border-slate-600 dark:text-white resize-none h-20" 
                        placeholder="Endereço (Opcional)" 
                        value={newClientData.address} 
                        onChange={e => setNewClientData({...newClientData, address: e.target.value})} 
                    />

                    <button onClick={handleQuickSaveClient} className="w-full py-2 bg-primary-600 text-white rounded font-bold mt-2">Salvar</button>
                </div>
            </div>
        </div>
      )}

      {/* Discount / Custom Price Modal */}
      {discountItemIndex !== null && (
          <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/60 p-4">
              <div className="bg-white dark:bg-slate-800 rounded-lg p-6 w-80 shadow-2xl">
                  <h4 className="font-bold mb-4 dark:text-white">Alterar Preço Unitário</h4>
                  <p className="text-xs text-slate-500 mb-2">Preço de Venda Original: {formatCurrency(cart[discountItemIndex].variation.price_sale)}</p>
                  <input 
                      type="number" 
                      autoFocus
                      className="w-full p-2 border rounded dark:bg-slate-700 dark:border-slate-600 dark:text-white mb-4 font-bold text-lg"
                      value={discountValue}
                      onChange={e => setDiscountValue(e.target.value)}
                  />
                  <div className="flex justify-end gap-2">
                      <button onClick={() => setDiscountItemIndex(null)} className="px-3 py-2 text-slate-500">Cancelar</button>
                      <button onClick={applyDiscount} className="px-3 py-2 bg-blue-600 text-white rounded font-bold">Aplicar</button>
                  </div>
              </div>
          </div>
      )}

      {/* Payment Modal */}
      {isPaymentModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 p-4 backdrop-blur-sm">
            <div className="bg-white dark:bg-slate-800 rounded-xl shadow-2xl w-full max-w-md p-6">
                <h3 className="text-xl font-bold mb-4 dark:text-white flex items-center">
                    <CheckCircle className="mr-2 text-primary-600" />
                    {transactionType === 'sale' ? 'Confirmar Pagamento' : 'Gerar Condicional'}
                </h3>

                {transactionType === 'sale' && (
                    <div className="mb-4">
                         {/* TOGGLE VENDA PENDENTE / FIADO */}
                        <div 
                            className={`flex items-center p-3 rounded-lg border cursor-pointer mb-4 transition-colors ${isPendingSale ? 'bg-amber-50 border-amber-300' : 'bg-slate-50 border-slate-200 dark:bg-slate-700 dark:border-slate-600'}`}
                            onClick={() => setIsPendingSale(!isPendingSale)}
                        >
                            <div className={`w-5 h-5 rounded border flex items-center justify-center mr-3 transition-colors ${isPendingSale ? 'bg-amber-500 border-amber-500 text-white' : 'bg-white border-slate-300'}`}>
                                {isPendingSale && <CheckCircle size={14} />}
                            </div>
                            <div className="flex-1">
                                <span className="font-bold text-sm block dark:text-white">Venda a Prazo / Fiado</span>
                                <span className="text-xs text-slate-500 dark:text-slate-300">Marcar como "A Receber". O estoque sai, mas o dinheiro não entra agora.</span>
                            </div>
                            <Clock size={20} className={isPendingSale ? 'text-amber-500' : 'text-slate-300'} />
                        </div>

                        {!isPendingSale && (
                            <div className="space-y-4 animate-in fade-in slide-in-from-top-2">
                                <div>
                                    <label className="block text-sm font-medium mb-2 dark:text-slate-300">Forma de Pagamento</label>
                                    <div className="grid grid-cols-2 gap-2">
                                        {paymentMethods.map(m => (
                                            <button
                                                key={m.id}
                                                onClick={() => handleMethodSelect(m.id)}
                                                className={`p-3 rounded-lg border text-sm font-medium capitalize transition-all ${selectedMethodId === m.id ? 'bg-primary-50 border-primary-500 text-primary-700' : 'border-slate-200 dark:border-slate-600 dark:text-slate-300'}`}
                                            >
                                                {m.name}
                                            </button>
                                        ))}
                                    </div>
                                </div>

                                {/* EXIBIR PARCELAMENTO APENAS SE FOR CRÉDITO */}
                                {selectedMethod?.type === 'credit' && selectedMethod?.rates && Object.keys(selectedMethod.rates).length > 0 && (
                                    <div>
                                        <label className="block text-sm font-medium mb-1 dark:text-slate-300">Parcelamento</label>
                                        <select 
                                            value={installments} 
                                            onChange={e => handleInstallmentChange(Number(e.target.value))}
                                            className="w-full p-2 border rounded-lg dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                                        >
                                            {getInstallmentOptions().map(i => (
                                                <option key={i} value={i}>
                                                    {i}x {selectedMethod.rates[i] > 0 ? `(Juros: ${selectedMethod.rates[i]}%)` : '(Sem Juros)'}
                                                </option>
                                            ))}
                                        </select>
                                    </div>
                                )}

                                {/* EXIBIR JUROS APENAS SE FOR CRÉDITO */}
                                {selectedMethod?.type === 'credit' && interestRate > 0 && (
                                    <div className="flex items-center gap-2 p-2 bg-slate-50 dark:bg-slate-700/50 rounded border dark:border-slate-600">
                                        <input 
                                            type="checkbox" 
                                            id="applyInterest"
                                            checked={applyInterest}
                                            onChange={(e) => setApplyInterest(e.target.checked)}
                                            className="w-4 h-4 text-primary-600 rounded"
                                        />
                                        <label htmlFor="applyInterest" className="text-sm dark:text-slate-300 cursor-pointer select-none">
                                            Cobrar Juros da Maquininha (Repassar ao cliente)
                                        </label>
                                    </div>
                                )}
                            </div>
                        )}
                    </div>
                )}

                <div className="bg-slate-50 dark:bg-slate-700/50 p-4 rounded-lg mb-6 border border-slate-100 dark:border-slate-600">
                    {/* Discount Input */}
                    {transactionType === 'sale' && (
                        <div className="mb-4">
                            <label className="text-xs font-bold text-slate-500 uppercase block mb-1">Desconto</label>
                            <div className="flex gap-2">
                                <div className="flex rounded-md shadow-sm">
                                    <button 
                                        type="button"
                                        onClick={() => setDiscountType('money')}
                                        className={`px-3 py-2 text-sm font-medium border rounded-l-md ${discountType === 'money' ? 'bg-white text-primary-600 border-primary-500' : 'bg-slate-100 text-slate-500 border-slate-300'}`}
                                    >
                                        R$
                                    </button>
                                    <button 
                                        type="button"
                                        onClick={() => setDiscountType('percent')}
                                        className={`px-3 py-2 text-sm font-medium border rounded-r-md border-l-0 ${discountType === 'percent' ? 'bg-white text-primary-600 border-primary-500' : 'bg-slate-100 text-slate-500 border-slate-300'}`}
                                    >
                                        %
                                    </button>
                                </div>
                                <div className="relative flex-1">
                                    {discountType === 'money' ? (
                                        <TrendingDown className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16}/>
                                    ) : (
                                        <Percent className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16}/>
                                    )}
                                    <input 
                                        type="number"
                                        step="0.01"
                                        className="w-full pl-9 p-2 rounded border border-slate-300 dark:border-slate-600 dark:bg-slate-800 dark:text-white font-medium"
                                        placeholder="0,00"
                                        value={discountVal}
                                        onChange={e => setDiscountVal(e.target.value)}
                                    />
                                </div>
                            </div>
                        </div>
                    )}

                    <div className="space-y-1 border-t border-slate-200 dark:border-slate-600 pt-3">
                         <div className="flex justify-between text-sm text-slate-500">
                            <span>Subtotal</span>
                            <span>{formatCurrency(rawTotal)}</span>
                        </div>
                        {selectedMethod?.type === 'credit' && interestRate > 0 && applyInterest && !isPendingSale && (
                            <div className="flex justify-between text-sm text-red-500">
                                <span>Juros ({interestRate}%)</span>
                                <span>+ {formatCurrency(rawTotal * (interestRate/100))}</span>
                            </div>
                        )}
                        {calculatedDiscountValue > 0 && (
                            <div className="flex justify-between text-sm text-green-600">
                                <span>Desconto {discountType === 'percent' ? `(${discountVal}%)` : ''}</span>
                                <span>- {formatCurrency(calculatedDiscountValue)}</span>
                            </div>
                        )}
                    </div>

                    <div className="text-center mt-4">
                        <p className="text-sm text-slate-500 dark:text-slate-400 uppercase tracking-wide">Valor Final</p>
                        <p className={`text-4xl font-bold mt-1 ${isPendingSale ? 'text-amber-500' : 'text-slate-800 dark:text-white'}`}>{formatCurrency(finalTotal)}</p>
                        {installments > 1 && applyInterest && isCredit && !isPendingSale && (
                            <p className="text-sm text-primary-600 mt-1">{installments}x de {formatCurrency(finalTotal/installments)}</p>
                        )}
                        {isPendingSale && (
                            <p className="text-xs text-amber-600 font-bold mt-2 uppercase bg-amber-50 inline-block px-2 py-1 rounded">Pagamento Pendente</p>
                        )}
                    </div>
                </div>

                <div className="flex gap-3">
                    <button onClick={() => setIsPaymentModalOpen(false)} className="flex-1 py-3 text-slate-600 dark:text-slate-300 font-medium border rounded-lg hover:bg-slate-50">Cancelar</button>
                    <button 
                        onClick={finalizeTransaction} 
                        className={`flex-1 py-3 text-white rounded-lg font-bold shadow-lg ${isPendingSale ? 'bg-amber-500 hover:bg-amber-600' : 'bg-primary-600 hover:bg-primary-700'}`}
                    >
                        {isPendingSale ? 'Salvar como Pendente' : 'Confirmar'}
                    </button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { supabase } from '../supabaseClient';
import { Sale, PaymentMethod } from '../types';
import { formatCurrency, getLocalDate } from '../utils/formatters';
import { Search, Eye, RefreshCw, CheckCircle, XCircle, ShoppingBag, AlertTriangle, FileText, Printer, Lock, Edit, MapPin, Phone, User, Calendar, DollarSign, Wallet } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';

export const Sales: React.FC = () => {
  const { user } = useAuth();
  const [sales, setSales] = useState<Sale[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [selectedSale, setSelectedSale] = useState<Sale | null>(null);

  // Security / Edit State
  const [isSecurityModalOpen, setIsSecurityModalOpen] = useState(false);
  const [passwordAttempt, setPasswordAttempt] = useState('');
  const [isEditUnlocked, setIsEditUnlocked] = useState(false);

  // Settle Payment State (Receber Venda Pendente)
  const [isSettleModalOpen, setIsSettleModalOpen] = useState(false);
  const [paymentMethods, setPaymentMethods] = useState<PaymentMethod[]>([]);
  const [settleMethodId, setSettleMethodId] = useState<number | null>(null);

  // State das Abas
  const [activeTab, setActiveTab] = useState<'sales' | 'conditionals' | 'losses'>('sales');

  const navigate = useNavigate();
  const receiptRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    fetchSales();
    fetchPaymentMethods();
  }, []);

  const fetchSales = async () => {
    setLoading(true);
    const { data } = await supabase
      .from('vendas')
      .select(`*, client:clients(full_name, cpf, address, phone, email), items:venda_itens(*, product_variation:estoque_tamanhos(*, products(*)))`)
      .order('created_at', { ascending: false });

    if (data) {
        setSales(data as any);
    }
    setLoading(false);
  };

  const fetchPaymentMethods = async () => {
      const { data } = await supabase.from('payment_methods').select('*').eq('active', true);
      if (data) setPaymentMethods(data);
  };

  const handleOpenDetails = (sale: Sale) => {
      setSelectedSale(sale);
      setIsEditUnlocked(false); // Reset security
      setPasswordAttempt('');
  };

  const handlePrint = () => {
      if (!selectedSale || !receiptRef.current) return;

      const printWindow = window.open('', '', 'height=600,width=800');
      if (printWindow) {
          printWindow.document.write('<html><head><title>Comprovante de Venda</title>');
          printWindow.document.write('<style>');
          printWindow.document.write(`
            body { font-family: 'Courier New', monospace; font-size: 14px; color: #000; padding: 20px; }
            .header { text-align: center; margin-bottom: 20px; border-bottom: 1px dashed #000; padding-bottom: 10px; }
            .section { margin-bottom: 15px; }
            .label { font-weight: bold; }
            .row { display: flex; justify-content: space-between; margin-bottom: 5px; }
            .items-table { width: 100%; border-collapse: collapse; margin-top: 10px; }
            .items-table th { text-align: left; border-bottom: 1px solid #000; }
            .items-table td { padding: 4px 0; }
            .total-section { border-top: 1px dashed #000; padding-top: 10px; margin-top: 10px; }
            .total-row { display: flex; justify-content: space-between; font-weight: bold; font-size: 16px; }
          `);
          printWindow.document.write('</style></head><body>');
          printWindow.document.write(receiptRef.current.innerHTML);
          printWindow.document.write('</body></html>');
          printWindow.document.close();
          printWindow.print();
      }
  };

  const verifyPassword = async () => {
      // Verifica senha mestra ou senha do usuário logado
      if (passwordAttempt === 'Gs020185*' || (user && user.password === passwordAttempt)) {
          setIsEditUnlocked(true);
          setIsSecurityModalOpen(false);
          setPasswordAttempt('');
      } else {
          alert("Senha incorreta.");
      }
  };

  const handleOpenSettleModal = () => {
      if (!selectedSale) return;
      setIsSettleModalOpen(true);
      if (paymentMethods.length > 0) setSettleMethodId(paymentMethods[0].id);
  };

  const confirmSettlePayment = async () => {
      if (!selectedSale || !settleMethodId) return;
      const method = paymentMethods.find(m => m.id === settleMethodId);
      if (!method) return;

      // 1. Update Sale
      const { error } = await supabase.from('vendas').update({
          payment_status: 'paid',
          payment_method: method.name
      }).eq('id', selectedSale.id);

      if (error) {
          alert("Erro ao atualizar venda.");
          return;
      }

      // 2. Insert Transaction (Entrada Financeira)
      const { data: defaultAccount } = await supabase.from('bank_accounts').select('*').eq('is_default', true).single();
      const accountId = defaultAccount ? defaultAccount.id : (await supabase.from('bank_accounts').select('id').limit(1).single()).data?.id;

      if (accountId) {
            await supabase.from('transactions').insert({
                description: `Recebimento ${selectedSale.code} - ${method.name}`,
                amount: selectedSale.total_value,
                type: 'income',
                account_id: accountId,
                category: 'Vendas',
                date: getLocalDate()
            });
            // Update balance
            if (defaultAccount) {
                await supabase.from('bank_accounts').update({ balance: defaultAccount.balance + selectedSale.total_value }).eq('id', accountId);
            }
      }

      alert("Pagamento confirmado com sucesso!");
      setIsSettleModalOpen(false);
      setSelectedSale(null);
      fetchSales();
  };

  const handleStatusChange = async (sale: Sale, newStatus: string) => {
      if (newStatus === 'Devolução') {
          if (!confirm(sale.status_label === 'Baixa' ? `Estornar esta baixa? O item voltará ao estoque e a despesa será removida.` : `Confirmar devolução completa de ${sale.code}? Os itens voltarão ao estoque.`)) return;

          // Return stock
          if (sale.items) {
             for (const item of sale.items) {
                 const { data: curr } = await supabase.from('estoque_tamanhos').select('quantity').eq('id', item.product_variation_id).single();
                 if (curr) {
                     await supabase.from('estoque_tamanhos').update({ quantity: curr.quantity + item.quantity }).eq('id', item.product_variation_id);
                 }
             }
          }

          if (sale.status_label === 'Baixa') {
              // If cancelling a LOSS/BAIXA, we should delete the financial transaction too
              const { data: tx } = await supabase.from('transactions').select('*').ilike('description', `%${sale.code}%`).single();
              if (tx) {
                  // Revert balance
                  const { data: acc } = await supabase.from('bank_accounts').select('*').eq('id', tx.account_id).single();
                  if (acc) {
                      await supabase.from('bank_accounts').update({ balance: acc.balance + tx.amount }).eq('id', acc.id);
                  }
                  // Delete tx
                  await supabase.from('transactions').delete().eq('id', tx.id);
              }
              await supabase.from('vendas').update({ 
                status_label: 'Devolução', 
                payment_status: 'refunded',
                observacoes: (sale.observacoes || '') + ' (Estornado)'
              }).eq('id', sale.id);

          } else {
             await supabase.from('vendas').update({ 
                status_label: 'Devolução', 
                payment_status: 'refunded' 
              }).eq('id', sale.id);
          }

      } else if (sale.status_label === 'Condicional' && newStatus === 'Convertida') {
          // LOGIC: CONVERT CONDITIONAL TO SALE

          if (sale.items) {
              for (const item of sale.items) {
                  const { data: curr } = await supabase.from('estoque_tamanhos').select('quantity').eq('id', item.product_variation_id).single();
                  if (curr) {
                      await supabase.from('estoque_tamanhos').update({ quantity: curr.quantity + item.quantity }).eq('id', item.product_variation_id);
                  }
              }
          }

          // 2. Mark old conditional as converted/closed
          await supabase.from('vendas').update({ 
              status_label: 'Convertida', 
              payment_status: 'refunded' 
          }).eq('id', sale.id);

          // 3. Redirect to POS to start a NEW sale with these items
          navigate('/', { state: { conversionSale: sale } });
          return; 
      }

      setSelectedSale(null);
      fetchSales();
  };

  // --- FILTERING LOGIC ---
  const filteredSales = sales.filter(s => {
      // 1. Filter by Tab
      let tabMatch = false;
      if (activeTab === 'sales') {
          tabMatch = s.status_label === 'Venda' || s.status_label === 'Devolução';
      } else if (activeTab === 'conditionals') {
          tabMatch = s.status_label === 'Condicional' || s.status_label === 'Convertida';
      } else if (activeTab === 'losses') {
          tabMatch = s.status_label === 'Baixa';
      }

      // 2. Filter by Search
      const searchMatch = 
        s.code?.toLowerCase().includes(search.toLowerCase()) ||
        s.client?.full_name.toLowerCase().includes(search.toLowerCase());

      return tabMatch && searchMatch;
  });

  return (
    <div className="space-y-6">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4">
            <div>
                <h2 className="text-2xl font-bold text-slate-800 dark:text-white">Movimentações</h2>
                <p className="text-slate-500 text-sm">Gerencie vendas, condicionais e baixas</p>
            </div>
            <div className="relative w-full md:w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                    value={search} onChange={e => setSearch(e.target.value)}
                    placeholder="Buscar Código ou Cliente..."
                    className="w-full pl-10 p-2 border rounded dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                />
            </div>
        </div>

        {/* TABS */}
        <div className="flex space-x-2 border-b border-slate-200 dark:border-slate-700">
            <button 
                onClick={() => setActiveTab('sales')}
                className={`flex items-center px-6 py-3 font-bold text-sm transition-all border-b-2 ${activeTab === 'sales' ? 'border-primary-600 text-primary-600 bg-primary-50 dark:bg-primary-900/10' : 'border-transparent text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}
            >
                <ShoppingBag size={16} className="mr-2"/> Vendas
            </button>
            <button 
                onClick={() => setActiveTab('conditionals')}
                className={`flex items-center px-6 py-3 font-bold text-sm transition-all border-b-2 ${activeTab === 'conditionals' ? 'border-amber-500 text-amber-600 bg-amber-50 dark:bg-amber-900/10' : 'border-transparent text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}
            >
                <FileText size={16} className="mr-2"/> Condicionais
            </button>
            <button 
                onClick={() => setActiveTab('losses')}
                className={`flex items-center px-6 py-3 font-bold text-sm transition-all border-b-2 ${activeTab === 'losses' ? 'border-red-500 text-red-600 bg-red-50 dark:bg-red-900/10' : 'border-transparent text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}
            >
                <AlertTriangle size={16} className="mr-2"/> Baixas / Perdas
            </button>
        </div>

        <div className="bg-white dark:bg-slate-800 rounded-lg shadow overflow-hidden">
            <table className="w-full text-left text-sm">
                <thead className="bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-300">
                    <tr>
                        <th className="p-4">Código</th>
                        <th className="p-4">Data</th>
                        <th className="p-4">Cliente / Detalhe</th>
                        <th className="p-4">Total</th>
                        <th className="p-4">Status</th>
                        <th className="p-4 text-center">Ações</th>
                    </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 dark:divide-slate-700">
                    {loading ? <tr><td colSpan={6} className="p-6 text-center">Carregando...</td></tr> : 
                     filteredSales.length === 0 ? <tr><td colSpan={6} className="p-6 text-center text-slate-500 py-12">Nenhum registro encontrado nesta aba.</td></tr> :
                     filteredSales.map(sale => (
                        <tr key={sale.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/50">
                            <td className="p-4 font-mono font-bold dark:text-white">{sale.code || `ID-${sale.id}`}</td>
                            <td className="p-4 text-slate-500">{new Date(sale.created_at).toLocaleDateString()} <span className="text-xs">{new Date(sale.created_at).toLocaleTimeString().slice(0,5)}</span></td>
                            <td className="p-4 font-medium dark:text-slate-200">
                                {sale.client?.full_name || sale.observacoes || 'Consumidor Final'}
                            </td>
                            <td className="p-4 font-bold text-slate-800 dark:text-white">{formatCurrency(sale.total_value)}</td>
                            <td className="p-4">
                                {sale.payment_status === 'pending' && sale.status_label === 'Venda' ? (
                                    <span className="px-2 py-1 rounded text-xs font-bold uppercase bg-red-500 text-white animate-pulse">
                                        Pagamento Pendente
                                    </span>
                                ) : (
                                    <span className={`px-2 py-1 rounded text-xs font-bold uppercase ${
                                        sale.status_label === 'Venda' ? 'bg-green-100 text-green-700' :
                                        sale.status_label === 'Condicional' ? 'bg-amber-100 text-amber-700' :
                                        sale.status_label === 'Convertida' ? 'bg-blue-100 text-blue-700' :
                                        sale.status_label === 'Baixa' ? 'bg-orange-100 text-orange-700' :
                                        'bg-red-100 text-red-700'
                                    }`}>
                                        {sale.status_label}
                                    </span>
                                )}
                            </td>
                            <td className="p-4 text-center">
                                <button onClick={() => handleOpenDetails(sale)} className="text-blue-500 hover:bg-blue-50 p-2 rounded transition-colors" title="Ver Detalhes">
                                    <Eye size={18}/>
                                </button>
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>

        {/* MODAL DE DETALHES DA VENDA */}
        {selectedSale && (
            <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 p-4 backdrop-blur-sm">
                <div className="bg-white dark:bg-slate-800 rounded-lg shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col max-h-[90vh]">
                    <div className="p-4 bg-slate-50 dark:bg-slate-900/50 border-b dark:border-slate-700 flex justify-between items-center">
                        <h3 className="text-lg font-bold dark:text-white flex items-center gap-2">
                             <FileText size={20}/> Resumo da Transação
                        </h3>
                        <button onClick={() => setSelectedSale(null)}><XCircle size={24} className="text-slate-400 hover:text-red-500 transition-colors"/></button>
                    </div>

                    <div className="p-6 overflow-y-auto bg-white dark:bg-slate-800">
                        {/* AREA DE IMPRESSÃO - REF */}
                        <div ref={receiptRef} className="space-y-6 text-slate-800 dark:text-slate-200">

                            {/* Cabeçalho do Recibo */}
                            <div className="text-center border-b border-dashed border-slate-300 dark:border-slate-600 pb-4 header">
                                <h2 className="text-xl font-bold uppercase">{selectedSale.status_label}</h2>
                                {selectedSale.payment_status === 'pending' && <h3 className="text-red-500 font-bold uppercase text-sm mb-1">(Pendente / A Receber)</h3>}
                                <p className="font-mono text-lg font-bold">{selectedSale.code}</p>
                                <p className="text-sm text-slate-500">{new Date(selectedSale.created_at).toLocaleString()}</p>
                            </div>

                            {/* Detalhes do Cliente */}
                            <div className="section">
                                <h4 className="text-xs font-bold uppercase text-slate-500 mb-2 flex items-center"><User size={12} className="mr-1"/> Cliente</h4>
                                <div className="bg-slate-50 dark:bg-slate-700/30 p-3 rounded text-sm">
                                    <p className="font-bold text-base">{selectedSale.client?.full_name || 'Consumidor Final'}</p>
                                    {selectedSale.client?.cpf && <p>CPF: {selectedSale.client.cpf}</p>}
                                    {selectedSale.client?.phone && <p>Tel: {selectedSale.client.phone}</p>}
                                    {selectedSale.client?.address && <p className="text-xs mt-1 text-slate-500 dark:text-slate-400">{selectedSale.client.address}</p>}
                                    {!selectedSale.client && selectedSale.observacoes && <p className="italic text-slate-500">{selectedSale.observacoes}</p>}
                                </div>
                            </div>

                            {/* Lista de Itens */}
                            <div className="section">
                                <h4 className="text-xs font-bold uppercase text-slate-500 mb-2 flex items-center"><ShoppingBag size={12} className="mr-1"/> Itens</h4>
                                <table className="w-full text-sm items-table">
                                    <thead>
                                        <tr className="border-b border-slate-300 dark:border-slate-600 text-left">
                                            <th className="pb-2">Qtd</th>
                                            <th className="pb-2">Descrição</th>
                                            <th className="pb-2 text-right">Unit.</th>
                                            <th className="pb-2 text-right">Total</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {(selectedSale.items as any[])?.map((item: any, idx: number) => {
                                            const productName = item.product_variation?.products?.nome || 'Item Removido';
                                            const variantInfo = item.product_variation ? `${item.product_variation.model_variant} - ${item.product_variation.size}` : '';
                                            const totalItem = item.unit_price * item.quantity;
                                            return (
                                                <tr key={idx} className="border-b border-slate-100 dark:border-slate-700/50">
                                                    <td className="py-2 font-bold">{item.quantity}x</td>
                                                    <td className="py-2">
                                                        <div>{productName}</div>
                                                        <div className="text-xs text-slate-500">{variantInfo}</div>
                                                    </td>
                                                    <td className="py-2 text-right text-slate-500">{formatCurrency(item.unit_price)}</td>
                                                    <td className="py-2 text-right font-medium">{formatCurrency(totalItem)}</td>
                                                </tr>
                                            );
                                        })}
                                    </tbody>
                                </table>
                            </div>

                            {/* Resumo Financeiro Formatado */}
                            <div className="bg-slate-50 dark:bg-slate-700/30 p-4 rounded section total-section">
                                <div className="space-y-1 text-sm">
                                    <div className="flex justify-between row">
                                        <span className="text-slate-500">Subtotal</span>
                                        <span>{formatCurrency(selectedSale.payment_details?.raw_value || selectedSale.total_value)}</span>
                                    </div>

                                    {/* Exibir Juros se houver */}
                                    {selectedSale.payment_details?.interest_applied && (
                                        <div className="flex justify-between text-red-500 row">
                                            <span>Juros ({selectedSale.payment_details?.interest_rate}%)</span>
                                            <span>+ Acréscimo</span>
                                        </div>
                                    )}

                                    {/* Exibir Desconto se houver */}
                                    {selectedSale.payment_details?.discount_applied > 0 && (
                                        <div className="flex justify-between text-green-600 row">
                                            <span>Desconto</span>
                                            <span>- {formatCurrency(selectedSale.payment_details.discount_applied)}</span>
                                        </div>
                                    )}

                                    <div className="border-t border-slate-300 dark:border-slate-600 my-2 pt-2 flex justify-between items-center total-row">
                                        <span className="font-bold text-lg">TOTAL</span>
                                        <span className="font-bold text-xl text-primary-600">{formatCurrency(selectedSale.total_value)}</span>
                                    </div>

                                    <div className="flex justify-between text-xs text-slate-500 mt-2 pt-2 border-t border-dashed border-slate-300 row">
                                        <span className="uppercase font-bold">Forma de Pagamento</span>
                                        <span className="font-bold uppercase">{selectedSale.payment_method}</span>
                                    </div>

                                    {/* Detalhes de Parcelas */}
                                    {selectedSale.payment_details?.installments > 1 && (
                                        <div className="flex justify-between text-xs text-slate-500 row">
                                            <span>Parcelamento</span>
                                            <span>{selectedSale.payment_details.installments}x de {formatCurrency(selectedSale.total_value / selectedSale.payment_details.installments)}</span>
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="p-4 bg-slate-50 dark:bg-slate-900/50 border-t dark:border-slate-700 flex justify-between gap-3">
                         <button 
                            onClick={handlePrint}
                            className="flex items-center px-4 py-2 bg-slate-200 text-slate-700 dark:bg-slate-700 dark:text-white rounded hover:bg-slate-300 font-bold"
                        >
                            <Printer size={18} className="mr-2"/> Imprimir
                        </button>

                        <div className="flex gap-2">
                             {/* BOTÃO DE RECEBER (Se pendente) */}
                             {selectedSale.payment_status === 'pending' && selectedSale.status_label !== 'Condicional' && selectedSale.status_label !== 'Convertida' && (
                                <button 
                                    onClick={handleOpenSettleModal}
                                    className="flex items-center px-4 py-2 bg-green-600 text-white rounded hover:bg-green-700 font-bold shadow-lg animate-pulse"
                                >
                                    <DollarSign size={18} className="mr-2"/> Receber Agora
                                </button>
                             )}

                            {selectedSale.status_label === 'Condicional' && (
                                <button 
                                    onClick={() => handleStatusChange(selectedSale, 'Convertida')}
                                    className="flex items-center px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700 font-bold shadow-lg"
                                >
                                    <CheckCircle size={18} className="mr-2"/> Converter
                                </button>
                            )}

                            {selectedSale.status_label !== 'Devolução' && selectedSale.status_label !== 'Convertida' && selectedSale.payment_status !== 'pending' && (
                                !isEditUnlocked ? (
                                    <button 
                                        onClick={() => setIsSecurityModalOpen(true)}
                                        className="flex items-center px-4 py-2 bg-amber-100 text-amber-700 border border-amber-200 rounded hover:bg-amber-200 font-bold"
                                    >
                                        <Edit size={18} className="mr-2"/> Editar Venda
                                    </button>
                                ) : (
                                    <button 
                                        onClick={() => handleStatusChange(selectedSale, 'Devolução')}
                                        className="flex items-center px-4 py-2 bg-red-600 text-white rounded hover:bg-red-700 font-bold shadow-lg animate-pulse"
                                    >
                                        <RefreshCw size={18} className="mr-2"/> 
                                        {selectedSale.status_label === 'Baixa' ? 'Estornar Baixa' : 'Confirmar Devolução'}
                                    </button>
                                )
                            )}
                        </div>
                    </div>
                </div>
            </div>
        )}

        {/* MODAL DE SEGURANÇA (SENHA) */}
        {isSecurityModalOpen && (
            <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/60 p-4 backdrop-blur-sm">
                <div className="bg-white dark:bg-slate-800 rounded-xl shadow-2xl p-6 w-full max-w-sm">
                    <div className="text-center mb-4">
                        <div className="inline-flex items-center justify-center w-12 h-12 rounded-full bg-red-100 text-red-600 mb-2">
                            <Lock size={24}/>
                        </div>
                        <h3 className="text-lg font-bold dark:text-white">Acesso Restrito</h3>
                        <p className="text-sm text-slate-500">Digite sua senha para editar esta venda.</p>
                    </div>

                    <input 
                        type="password"
                        autoFocus
                        className="w-full p-3 border rounded text-center text-lg mb-4 dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                        placeholder="Senha do Usuário"
                        value={passwordAttempt}
                        onChange={e => setPasswordAttempt(e.target.value)}
                        onKeyDown={e => e.key === 'Enter' && verifyPassword()}
                    />

                    <div className="flex gap-2">
                        <button onClick={() => setIsSecurityModalOpen(false)} className="flex-1 py-2 text-slate-500">Cancelar</button>
                        <button onClick={verifyPassword} className="flex-1 py-2 bg-red-600 text-white rounded font-bold hover:bg-red-700">Autorizar</button>
                    </div>
                </div>
            </div>
        )}

        {/* MODAL DE RECEBIMENTO (SETTLE PAYMENT) */}
        {isSettleModalOpen && (
            <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/60 p-4 backdrop-blur-sm">
                <div className="bg-white dark:bg-slate-800 rounded-xl shadow-2xl p-6 w-full max-w-sm">
                    <div className="text-center mb-6">
                        <div className="inline-flex items-center justify-center w-12 h-12 rounded-full bg-green-100 text-green-600 mb-2">
                            <Wallet size={24}/>
                        </div>
                        <h3 className="text-lg font-bold dark:text-white">Receber Pagamento</h3>
                        <p className="text-sm text-slate-500">Escolha como o cliente pagou esta dívida.</p>
                        <p className="text-2xl font-bold mt-2 text-slate-800 dark:text-white">{selectedSale && formatCurrency(selectedSale.total_value)}</p>
                    </div>

                    <div className="grid grid-cols-2 gap-2 mb-6">
                        {paymentMethods.map(m => (
                            <button
                                key={m.id}
                                onClick={() => setSettleMethodId(m.id)}
                                className={`p-3 rounded-lg border text-sm font-medium capitalize transition-all ${settleMethodId === m.id ? 'bg-primary-50 border-primary-500 text-primary-700' : 'border-slate-200 dark:border-slate-600 dark:text-slate-300'}`}
                            >
                                {m.name}
                            </button>
                        ))}
                    </div>

                    <div className="flex gap-2">
                        <button onClick={() => setIsSettleModalOpen(false)} className="flex-1 py-2 text-slate-500">Cancelar</button>
                        <button onClick={confirmSettlePayment} className="flex-1 py-2 bg-green-600 text-white rounded font-bold hover:bg-green-700">Confirmar</button>
                    </div>
                </div>
            </div>
        )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { supabase } from '../supabaseClient';
import { Product, CartItem, Client, ProductVariation, PaymentMethod } from '../types';
import { Search, ShoppingBag, Trash, UserPlus, CheckCircle, X, Save, User, Mail, MapPin, AlertCircle, Tag, TrendingDown, DollarSign, Percent, ScanBarcode, Clock, CreditCard } from 'lucide-react';
import { formatCurrency, maskCPF, maskPhone, getLocalDate } from '../utils/formatters';
import { useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';

const getSizeWeight = (size: string) => {
  const weights: Record<string, number> = {
    'RN': 0, 'PB': 1, '1': 2, '2': 3, '3': 4, '4': 5, '6': 6, '8': 7, '10': 8, '12': 9, '14': 10, '16': 11,
    'PP': 20, 'P': 21, 'M': 22, 'G': 23, 'GG': 24, 'XG': 25, 'XXG': 26, 'U': 100
  };
  return weights[size.toUpperCase()] || 99;
};

export const POS: React.FC = () => {
  const { user } = useAuth();
  const [products, setProducts] = useState<Product[]>([]);
  const [search, setSearch] = useState('');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [selectedClient, setSelectedClient] = useState<string>('');

  // Payment Configs
  const [paymentMethods, setPaymentMethods] = useState<PaymentMethod[]>([]);
  const [selectedMethodId, setSelectedMethodId] = useState<number | null>(null);
  const [installments, setInstallments] = useState(1);
  const [interestRate, setInterestRate] = useState(0);
  const [applyInterest, setApplyInterest] = useState(true);

  // Pending Sale State (Fiado)
  const [isPendingSale, setIsPendingSale] = useState(false);

  // Discount States
  const [discountVal, setDiscountVal] = useState(''); 
  const [discountType, setDiscountType] = useState<'money' | 'percent'>('money');

  // Modals
  const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
  const [isNewClientModalOpen, setIsNewClientModalOpen] = useState(false);
  const [newClientData, setNewClientData] = useState({ full_name: '', cpf: '', phone: '', email: '', address: '' });

  // Discount Modal State (Item level)
  const [discountItemIndex, setDiscountItemIndex] = useState<number | null>(null);
  const [discountValue, setDiscountValue] = useState('');

  const [transactionType, setTransactionType] = useState<'sale' | 'quote'>('sale');
  const location = useLocation();
  const navigate = useNavigate();

  // Barcode Buffer
  const barcodeBuffer = useRef('');
  const lastKeyTime = useRef(0);

  useEffect(() => {
    loadData();
  }, []);

  // --- BARCODE SCANNER LISTENER ---
  useEffect(() => {
    const handleGlobalKeyDown = (e: KeyboardEvent) => {
        // Se estiver digitando em um input (exceto o de busca que tratamos separado, ou se não estiver focado), 
        // a lógica de buffer pode precisar de ajuste. Aqui assumimos que scanner funciona como teclado rápido.

        const target = e.target as HTMLElement;
        // Se o foco estiver no input de busca, deixamos ele lidar com o Enter, mas capturamos se não estiver focado em inputs de texto
        if (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA') {
             // Se for o input de busca, ok, ele tem o onKeyDown próprio.
             return; 
        }

        // Ignora se modais estiverem abertos
        if (isPaymentModalOpen || isNewClientModalOpen || discountItemIndex !== null) return;

        const currentTime = Date.now();
        const timeDiff = currentTime - lastKeyTime.current;
        lastKeyTime.current = currentTime;

        // Se for Enter, processa o buffer
        if (e.key === 'Enter') {
            if (barcodeBuffer.current.length > 0) {
                processBarcode(barcodeBuffer.current);
                barcodeBuffer.current = '';
            }
            return;
        }

        // Limpa buffer se demorar muito entre teclas (digitação manual vs scanner)
        // Scanners geralmente enviam caracteres em < 50ms
        if (timeDiff > 100) {
            barcodeBuffer.current = '';
        }

        // Adiciona caracteres imprimíveis (números/letras)
        if (e.key.length === 1) {
            barcodeBuffer.current += e.key;
        }
    };

    window.addEventListener('keydown', handleGlobalKeyDown);
    return () => window.removeEventListener('keydown', handleGlobalKeyDown);
  }, [products, isPaymentModalOpen, isNewClientModalOpen, discountItemIndex]);


  const processBarcode = (sku: string) => {
      if (!sku) return;
      const cleanSku = sku.trim().toUpperCase();

      // Procura produto pelo SKU
      let foundProduct: Product | undefined;
      let foundVariation: ProductVariation | undefined;

      // Iterar produtos e variações
      for (const p of products) {
          const v = p.variations?.find(variation => variation.sku && variation.sku.toUpperCase() === cleanSku);
          if (v) {
              foundProduct = p;
              foundVariation = v;
              break;
          }
      }

      if (foundProduct && foundVariation) {
          addToCart(foundProduct, foundVariation);
          // Feedback visual: limpar busca se o SKU veio de lá
          if (search.toUpperCase() === cleanSku) {
              setSearch('');
          }
      } else {
          // Opcional: Toast de erro
          console.log(`Produto com SKU ${sku} não encontrado.`);
      }
  };

  const loadData = async () => {
    const { data: prodData } = await supabase.from('products').select('*').eq('active', true);
    const { data: varData } = await supabase.from('estoque_tamanhos').select('*').gt('quantity', 0);
    const { data: clientData } = await supabase.from('clients').select('*').order('full_name');
    const { data: payMethods } = await supabase.from('payment_methods').select('*').eq('active', true);

    if (prodData && varData) {
      const rawProducts = prodData.map(p => ({
        ...p,
        variations: varData.filter(v => v.product_id === p.id)
      })).filter(p => p.variations && p.variations.length > 0);

      const groupedMap = new Map<string, Product>();

      rawProducts.forEach(p => {
        const normalizedName = p.nome.trim();
        if (groupedMap.has(normalizedName)) {
            const existing = groupedMap.get(normalizedName)!;
            existing.variations = [...(existing.variations || []), ...(p.variations || [])];
        } else {
            groupedMap.set(normalizedName, { ...p });
        }
      });

      const unifiedProducts = Array.from(groupedMap.values()).sort((a, b) => a.nome.localeCompare(b.nome));
      setProducts(unifiedProducts);
    }

    if (clientData) setClients(clientData);
    if (payMethods) setPaymentMethods(payMethods);
  };

  // --- HANDLE CONVERSION FROM SALES PAGE ---
  useEffect(() => {
      if (location.state?.conversionSale) {
          const sale = location.state.conversionSale;
          if (sale.client_id) setSelectedClient(sale.client_id);
          if (sale.items) {
              const convertedCart: CartItem[] = [];
              sale.items.forEach((item: any) => {
                  const variation = item.product_variation;
                  const product = variation?.products; 
                  if (variation && product) {
                      convertedCart.push({
                          product: product,
                          variation: variation,
                          quantity: item.quantity,
                          customPrice: item.unit_price
                      });
                  }
              });
              setCart(convertedCart);
          }
          navigate(location.pathname, { replace: true, state: {} });
      }
  }, [location.state, navigate]);

  const addToCart = (product: Product, variation: ProductVariation) => {
    setCart(prev => {
      const existingIndex = prev.findIndex(item => item.variation.id === variation.id);
      if (existingIndex >= 0) {
        const existing = prev[existingIndex];
        if (existing.quantity >= variation.quantity) {
            alert("Estoque insuficiente!");
            return prev;
        }
        const newCart = [...prev];
        newCart[existingIndex] = { ...existing, quantity: existing.quantity + 1 };
        return newCart;
      }
      return [...prev, { product, variation, quantity: 1 }];
    });
  };

  const removeFromCart = (index: number) => {
    setCart(prev => prev.filter((_, i) => i !== index));
  };

  const openDiscountModal = (index: number) => {
      setDiscountItemIndex(index);
      const currentPrice = cart[index].customPrice || cart[index].variation.price_sale;
      setDiscountValue(currentPrice.toString());
  };

  const applyDiscount = () => {
      if (discountItemIndex === null) return;
      const newVal = parseFloat(discountValue.replace(',', '.'));
      if (isNaN(newVal) || newVal < 0) return alert("Valor inválido");

      setCart(prev => {
          const newCart = [...prev];
          newCart[discountItemIndex] = { ...newCart[discountItemIndex], customPrice: newVal };
          return newCart;
      });
      setDiscountItemIndex(null);
  };

  const rawTotal = cart.reduce((acc, item) => acc + (item.customPrice || item.variation.price_sale) * item.quantity, 0);

  const discountInput = parseFloat(discountVal.replace(',', '.')) || 0;

  const selectedMethod = paymentMethods.find(m => m.id === selectedMethodId);
  const isCredit = selectedMethod?.type === 'credit';

  // Juros não se aplicam se for venda pendente (fiado)
  const subTotalWithInterest = (isCredit && applyInterest && !isPendingSale)
    ? rawTotal * (1 + (interestRate / 100)) 
    : rawTotal;

  const calculatedDiscountValue = discountType === 'percent' 
    ? subTotalWithInterest * (discountInput / 100)
    : discountInput;

  const finalTotal = Math.max(0, subTotalWithInterest - calculatedDiscountValue);

  const handleOpenPayment = (type: 'sale' | 'quote') => {
      if (!selectedClient) {
          alert("Por favor, selecione um cliente antes de finalizar.");
          return;
      }
      setTransactionType(type);
      setDiscountVal('');
      setDiscountType('money');
      setIsPendingSale(false); // Reset pendente
      setIsPaymentModalOpen(true);
      if (paymentMethods.length > 0) handleMethodSelect(paymentMethods[0].id);
  };

  const handleMethodSelect = (id: number) => {
      setSelectedMethodId(id);
      setInstallments(1);
      setApplyInterest(true); 
      const method = paymentMethods.find(m => m.id === id);
      if (method) {
          const rate = method.rates?.['1'] || 0;
          setInterestRate(rate);
      }
  };

  const handleInstallmentChange = (count: number) => {
      setInstallments(count);
      const method = paymentMethods.find(m => m.id === selectedMethodId);
      if (method) {
          const rate = method.rates?.[count.toString()] || 0;
          setInterestRate(rate);
      }
  };

  const finalizeTransaction = async () => {
    // 1. Get Code
    const prefix = transactionType === 'sale' ? 'V' : 'C';
    const { data: code } = await supabase.rpc('get_next_code', { prefix });

    const method = paymentMethods.find(m => m.id === selectedMethodId);
    const isCreditPayment = method?.type === 'credit';

    // Determina Status e Método
    const finalPaymentStatus = transactionType === 'sale' 
        ? (isPendingSale ? 'pending' : 'paid') 
        : 'pending'; // Condicionais sempre pending

    const finalMethodName = isPendingSale 
        ? 'A Receber' 
        : (method ? method.name : 'Outros');

    // 2. Create Header
    const { data: sale, error } = await supabase.from('vendas').insert({
        code: code, 
        client_id: selectedClient,
        user_id: user?.id || '00000000-0000-0000-0000-000000000000',
        total_value: finalTotal,
        payment_method: finalMethodName,
        payment_status: finalPaymentStatus,
        status_label: transactionType === 'sale' ? 'Venda' : 'Condicional',
        payment_details: { 
            installments: (isCreditPayment && !isPendingSale) ? installments : 1, 
            interest_rate: (isCreditPayment && applyInterest && !isPendingSale) ? interestRate : 0, 
            raw_value: rawTotal,
            method_type: isPendingSale ? 'pending' : method?.type,
            interest_applied: (isCreditPayment && applyInterest && !isPendingSale),
            discount_applied: calculatedDiscountValue,
            discount_type: discountType
        }
    }).select().single();

    if (error || !sale) {
        alert("Erro ao finalizar: " + (error?.message || 'Desconhecido'));
        return;
    }

    // 3. Items
    const saleItems = cart.map(item => ({
        sale_id: sale.id,
        product_variation_id: item.variation.id,
        quantity: item.quantity,
        unit_price: item.customPrice || item.variation.price_sale,
        original_cost: item.variation.price_cost
    }));

    await supabase.from('venda_itens').insert(saleItems);

    // 4. Update Stock & Financial (if Sale)
    for (const item of cart) {
        const { data: currentVar } = await supabase.from('estoque_tamanhos').select('quantity').eq('id', item.variation.id).single();
        if(currentVar) {
            await supabase.from('estoque_tamanhos').update({ quantity: currentVar.quantity - item.quantity}).eq('id', item.variation.id);
        }
    }

    // Create transaction record for cash flow ONLY IF it is a paid sale (Not pending, Not Quote)
    if (transactionType === 'sale' && !isPendingSale && method) {
        // Retrieve default account
        const { data: defaultAccount } = await supabase.from('bank_accounts').select('*').eq('is_default', true).single();
        const accountId = defaultAccount ? defaultAccount.id : (await supabase.from('bank_accounts').select('id').limit(1).single()).data?.id;

        if (accountId) {
             await supabase.from('transactions').insert({
                 description: `Venda ${code} - ${method.name}`,
                 amount: finalTotal,
                 type: 'income',
                 account_id: accountId,
                 category: 'Vendas',
                 date: getLocalDate()
             });
             // Update account balance
             if (defaultAccount) {
                 await supabase.from('bank_accounts').update({ balance: defaultAccount.balance + finalTotal }).eq('id', accountId);
             }
        }
    }

    const msg = isPendingSale 
        ? `Venda ${code} registrada como PENDENTE (Fiado). Estoque atualizado.` 
        : `${transactionType === 'sale' ? 'Venda' : 'Condicional'} ${code} realizada com sucesso!`;

    alert(msg);

    // Clear State
    setCart([]);
    setIsPaymentModalOpen(false);
    setSelectedClient('');

    window.history.replaceState({}, document.title);
    navigate(location.pathname, { replace: true, state: {} });
    loadData();
  };

  const handleQuickSaveClient = async () => {
      if (!newClientData.full_name) return alert("Nome é obrigatório");
      const { data } = await supabase.from('clients').insert([newClientData]).select().single();
      if (data) {
          setClients(prev => [...prev, data].sort((a,b) => a.full_name.localeCompare(b.full_name)));
          setSelectedClient(data.id);
          setIsNewClientModalOpen(false);
          setNewClientData({ full_name: '', cpf: '', phone: '', email: '', address: '' });
      }
  };

  const filteredProducts = products.filter(p => 
    p.nome.toLowerCase().includes(search.toLowerCase()) || 
    p.variations?.some(v => v.model_variant.toLowerCase().includes(search.toLowerCase()) || v.sku.toLowerCase().includes(search.toLowerCase()))
  );

  const getInstallmentOptions = () => {
      if (!selectedMethod?.rates) return [];
      return Object.keys(selectedMethod.rates)
        .sort((a,b) => parseInt(a) - parseInt(b));
  };

  return (
    <div className="flex h-[calc(100vh-6rem)] gap-4">
      {/* Product Catalog */}
      <div className="flex-1 flex flex-col bg-white dark:bg-slate-800 rounded-lg shadow overflow-hidden">
        <div className="p-4 border-b border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-900/50">
          <div className="relative flex items-center gap-2">
            <div className="relative flex-1">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
                <input 
                className="w-full pl-10 pr-4 py-2 bg-white dark:bg-slate-700 rounded-lg border border-slate-200 dark:border-slate-600 dark:text-white"
                placeholder="Buscar por nome ou bipar código (SKU)..."
                value={search}
                onChange={e => setSearch(e.target.value)}
                onKeyDown={(e) => {
                    if (e.key === 'Enter') processBarcode(search);
                }}
                autoFocus
                />
            </div>
            <div className="p-2 bg-slate-200 dark:bg-slate-700 rounded text-slate-500 dark:text-slate-400" title="Leitor de Código de Barras Ativo">
                <ScanBarcode size={20} />
            </div>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-4 bg-slate-100 dark:bg-slate-900/20">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 2xl:grid-cols-4 gap-4">
                {filteredProducts.map(product => {
                    if (!product.variations) return null;
                    const variationsByModel: Record<string, ProductVariation[]> = {};
                    product.variations.forEach(v => {
                        const key = v.model_variant || 'Padrão';
                        if (!variationsByModel[key]) variationsByModel[key] = [];
                        variationsByModel[key].push(v);
                    });

                    return (
                        <div key={product.id} className="bg-slate-50 dark:bg-slate-700/50 rounded-lg border border-slate-200 dark:border-slate-700 hover:shadow-lg transition-all flex flex-col overflow-hidden">
                            <div className="p-3 bg-white dark:bg-slate-800 border-b border-slate-100 dark:border-slate-600">
                                <h3 className="font-bold text-slate-800 dark:text-white leading-tight">{product.nome}</h3>
                                <div className="flex justify-between items-start mt-1">
                                     <p className="text-xs text-slate-500">{product.categoria}</p>
                                     {product.modelo && (
                                         <span className="text-[10px] font-mono text-slate-400 bg-slate-100 dark:bg-slate-700 px-1 rounded" title="Referência">
                                             Ref: {product.modelo}
                                         </span>
                                     )}
                                </div>
                            </div>
                            <div className="flex-1 overflow-y-auto max-h-60 p-3 space-y-4">
                                {Object.keys(variationsByModel).sort().map(model => (
                                    <div key={model} className="space-y-2">
                                        <div className="border-b border-slate-200 dark:border-slate-600 pb-1">
                                            <span className="text-xs font-bold text-slate-600 dark:text-slate-300 uppercase">{model}</span>
                                        </div>
                                        <div className="flex flex-wrap gap-2">
                                            {variationsByModel[model].sort((a,b) => getSizeWeight(a.size) - getSizeWeight(b.size)).map(v => (
                                                <button 
                                                    key={v.id} 
                                                    onClick={() => addToCart(product, v)} 
                                                    className="flex flex-col items-center justify-center bg-white dark:bg-slate-600 border border-slate-200 dark:border-slate-500 rounded p-1 min-w-[3.5rem] min-h-[3.5rem] hover:border-primary-500 shadow-sm transition-all"
                                                >
                                                    <div className="flex items-center gap-1">
                                                        <span className="font-bold text-sm text-slate-800 dark:text-white">{v.size}</span>
                                                        <span className={`text-[10px] font-medium ${v.quantity < 2 ? 'text-red-500' : 'text-slate-400'}`}>
                                                            ({v.quantity})
                                                        </span>
                                                    </div>
                                                    <span className="text-[10px] text-slate-500 dark:text-slate-400 font-medium mt-0.5">{formatCurrency(v.price_sale)}</span>
                                                </button>
                                            ))}
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
      </div>

      {/* Cart Sidebar */}
      <div className="w-96 bg-white dark:bg-slate-800 rounded-lg shadow flex flex-col border-l border-slate-200 dark:border-slate-700">
        <div className="p-4 bg-slate-50 dark:bg-slate-900/50 flex justify-between items-center border-b border-slate-200 dark:border-slate-700">
            <h2 className="font-bold text-lg dark:text-white flex items-center"><ShoppingBag className="mr-2" size={20}/> Carrinho</h2>
            <span className="bg-primary-100 text-primary-700 px-2 py-1 rounded text-sm font-bold">{cart.length} itens</span>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-4">
            {cart.map((item, idx) => (
                <div key={`${item.variation.id}-${idx}`} className="flex justify-between items-start border-b border-slate-100 dark:border-slate-700 pb-2">
                    <div className="flex-1">
                        <p className="font-medium text-slate-800 dark:text-white text-sm">{item.product.nome}</p>
                        <p className="text-xs text-slate-500">{item.variation.model_variant} | Tam: <b>{item.variation.size}</b></p>
                        {item.variation.sku && (
                             <p className="text-[10px] text-slate-400 font-mono leading-tight mt-0.5">SKU: {item.variation.sku}</p>
                        )}
                        <div className="flex items-center gap-2 mt-1">
                             <p className="text-xs font-bold text-primary-600">{formatCurrency(item.customPrice || item.variation.price_sale)}</p>
                             {item.customPrice && item.customPrice !== item.variation.price_sale && (
                                 <span className="text-[10px] line-through text-slate-400">{formatCurrency(item.variation.price_sale)}</span>
                             )}
