                        <span className="font-mono font-bold text-slate-700 dark:text-slate-300 text-sm">x{item.quantity}</span>
                        <button onClick={() => removeFromCart(idx)} className="text-red-400 hover:text-red-600 p-1"><Trash size={16} /></button>
                    </div>
                </div>
